    return norm.pdf(d1) / (S * sigma * np.sqrt(T))

import numpy as np
def sharpe_ratio(returns, rf=0.02):
    daily_rf = (1 + rf)**(1/252) - 1
    excess = np.array(returns) - daily_rf
    return np.mean(excess) / np.std(excess) * np.sqrt(252)

