def find_iv(market_price, S, K, T, r):
    sigma = 0.2
    for i in range(100):
        diff = black_scholes_call(S,K,T,r,sigma) - market_price
        if abs(diff) < 0.0001: return sigma
        sigma -= diff / calculate_vega(S,K,T,r,sigma)

import numpy as np
def sortino_ratio(returns, target=0):
    downside = [r for r in returns if r < target]
    return np.mean(returns) / np.std(downside)

