from scipy.stats import norm
import numpy as np
def calculate_vega(S, K, T, r, sigma):
    d1 = (np.log(S/K) + (r + 0.5*sigma**2)*T) / (sigma*np.sqrt(T))
    return S * norm.pdf(d1) * np.sqrt(T)

def min_var_weights(s1, s2, cov):
    w1 = (s2**2 - cov) / (s1**2 + s2**2 - 2*cov)
    return w1, 1-w1
